1251:    function _calculateBorrowRate(address token) internal view returns (uint256 rateBps) {
1252:        LiquidityPool memory pool = pools[token];
1253:        if (pool.totalLiquidity == 0) return MIN_BORROWER_RATE;	// @audit-issue
1254:        
1255:        RateCurveParams memory curve = _poolRateCurve[token];
1256:        
1257:        // Calculate utilization: U = borrowedAmount * 10000 / totalLiquidity
1258:        uint256 utilization = (pool.borrowedAmount * 10000) / pool.totalLiquidity;
1259:        
1260:        // Piecewise linear model (multiply first, divide last to avoid precision loss)
1261:        if (utilization <= curve.optimalUtilizationBps) {
1262:            // Below optimal: baseRate + (borrowedAmount * 10000 * slope1) / (totalLiquidity * optimalUtil)
1263:            // This combines the utilization calculation with the slope calculation
1264:            uint256 slopeContribution = (pool.borrowedAmount * 10000 * curve.slope1Bps) / 
1265:                (pool.totalLiquidity * curve.optimalUtilizationBps);
1266:            rateBps = curve.baseRateBps + slopeContribution;
1267:        } else {
1268:            // Above optimal: baseRate + slope1 + ((U - optimalUtil) * slope2) / (10000 - optimalUtil)
1269:            uint256 excessUtil = utilization - curve.optimalUtilizationBps;
1270:            uint256 remainingUtil = 10000 - curve.optimalUtilizationBps;
1271:            // Multiply first: (excessUtil * slope2Bps) / remainingUtil
1272:            uint256 excessContribution = (excessUtil * curve.slope2Bps) / remainingUtil;
1273:            rateBps = curve.baseRateBps + curve.slope1Bps + excessContribution;
1274:        }
1275:        
1276:        // Clamp to min/max bounds
1277:        if (rateBps < MIN_BORROWER_RATE) rateBps = MIN_BORROWER_RATE;
1278:        if (rateBps > MAX_BORROWER_RATE) rateBps = MAX_BORROWER_RATE;
1279:        
1280:        return rateBps;
1281:    }

