133:    function initialize(	// @audit-issue
134:        address _defaultToken,
135:        uint256 _blockTimeSeconds,
136:        address initialOwner,
137:        uint256 _defaultMinLoanAmount,
138:        uint256 _defaultMaxLoanAmount
139:    ) public initializer {
140:        if (initialOwner == address(0)) revert UnllooErrors.InvalidOwner(initialOwner);
141:        if (_defaultToken == address(0)) revert UnllooErrors.InvalidDefaultToken(address(0));
142:        if (_blockTimeSeconds == 0 || _blockTimeSeconds > 86400) revert UnllooErrors.InvalidBlockTime(_blockTimeSeconds);
143:
144:        if (_defaultMinLoanAmount == 0 || _defaultMaxLoanAmount == 0) {
145:            revert UnllooErrors.InvalidPoolLoanLimits(_defaultMinLoanAmount, _defaultMaxLoanAmount);
146:        }
147:        if (_defaultMinLoanAmount >= _defaultMaxLoanAmount) {
148:            revert UnllooErrors.InvalidPoolLoanLimits(_defaultMinLoanAmount, _defaultMaxLoanAmount);
149:        }
150:
151:        __Ownable_init(initialOwner);
152:        __Pausable_init();
153:        __ReentrancyGuard_init();
154:
155:        defaultToken = _defaultToken;
156:        BLOCK_TIME_SECONDS = _blockTimeSeconds;
157:
158:        _validateTokenDecimals(_defaultToken);
159:
160:        pools[_defaultToken] = LiquidityPool({ token: _defaultToken, totalLiquidity: 0, borrowedAmount: 0 });
161:        minLoanAmountPerPool[_defaultToken] = _defaultMinLoanAmount;
162:        maxLoanAmountPerPool[_defaultToken] = _defaultMaxLoanAmount;
163:
164:        // supply index starts at 1e18
165:        poolSupplyIndex[_defaultToken] = 1e18;
166:
167:        // Set default rate curve for default pool
168:        _poolRateCurve[_defaultToken] = RateCurveParams({
169:            baseRateBps: DEFAULT_BASE_RATE_BPS,
170:            optimalUtilizationBps: DEFAULT_OPTIMAL_UTILIZATION_BPS,
171:            slope1Bps: DEFAULT_SLOPE1_BPS,
172:            slope2Bps: DEFAULT_SLOPE2_BPS,
173:            protocolFeeBps: DEFAULT_PROTOCOL_FEE_BPS
174:        });
175:
176:        minReputation = 200;
177:
178:        // Calculate blocks per day (multiply first, divide last to avoid precision loss)
179:        uint256 secondsPerDay = 24 * 60 * 60;
180:        uint256 blocksPerDay = secondsPerDay / BLOCK_TIME_SECONDS;
181:        if (blocksPerDay == 0) revert UnllooErrors.InvalidBlockTime(_blockTimeSeconds);
182:        
183:        // Calculate duration constants (multiply first, divide last)
184:        MIN_LOAN_DURATION_BLOCKS = blocksPerDay;
185:        MAX_LOAN_DURATION_BLOCKS = (secondsPerDay * 60) / BLOCK_TIME_SECONDS; // 60 days
186:        APPROVED_LOAN_EXPIRY_BLOCKS = (secondsPerDay * 30) / BLOCK_TIME_SECONDS; // 30 days
187:        cooldownBlocks = blocksPerDay;
188:    }

191:    function submitLoanRequest(	// @audit-issue
192:        uint16 walletReputation,
193:        address token,
194:        uint256 loanAmount,
195:        uint256 loanDurationBlocks
196:    ) external override whenNotPaused nonReentrant returns (uint256 loanId) {
197:        if (walletReputation < minReputation || walletReputation > 1000) {
198:            revert UnllooErrors.InvalidReputation(walletReputation, minReputation);
199:        }
200:        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);
201:
202:        (uint256 minLoanAmountToken, uint256 maxLoanAmountToken) = _getLoanLimits(token);
203:
204:        if (loanAmount < minLoanAmountToken || loanAmount > maxLoanAmountToken) {
205:            revert UnllooErrors.InvalidAmount(loanAmount, minLoanAmountToken, maxLoanAmountToken);
206:        }
207:        if (loanDurationBlocks < MIN_LOAN_DURATION_BLOCKS || loanDurationBlocks > MAX_LOAN_DURATION_BLOCKS) {
208:            revert UnllooErrors.InvalidDuration(loanDurationBlocks, MIN_LOAN_DURATION_BLOCKS, MAX_LOAN_DURATION_BLOCKS);
209:        }
210:        if (hasUnpaidDebt(msg.sender)) revert UnllooErrors.HasUnpaidDebt(msg.sender);
211:        if (openRequestCount[msg.sender] >= MAX_PENDING_LOANS_PER_USER) revert UnllooErrors.ExceedsMaxPendingLoans(msg.sender);
212:        if (_activeLoanByBorrower[msg.sender] != 0) revert UnllooErrors.HasActiveLoan(msg.sender);
213:
214:        if (lastRequestBlock[msg.sender] > 0) {
215:            uint256 cooldownEnd = lastRequestBlock[msg.sender] + cooldownBlocks;
216:            if (block.number < cooldownEnd) revert UnllooErrors.CooldownNotExpired(msg.sender, cooldownEnd);
217:        }
218:
219:        loanId = ++loanCounter;
220:
221:        loans[loanId] = Loan({
222:            loanId: loanId,
223:            borrower: msg.sender,
224:            status: LoanStatus.Pending,
225:            walletReputation: walletReputation,
226:            loanAmount: loanAmount,
227:            loanDurationBlocks: loanDurationBlocks,
228:            chainId: block.chainid,
229:            requestBlock: block.number,
230:            approvalBlock: 0,
231:            token: token,
232:            principal: 0,
233:            amountRepaid: 0, // informational only; not used for debt math
234:            startBlock: 0,
235:            deadlineBlock: 0,
236:            protocolFee: 0,
237:            interestAccrued: 0,
238:            borrowRateBps: 0,
239:            lastAccrualBlock: 0
240:        });
241:
242:        _borrowerLoans[msg.sender].push(loanId);
243:        UnllooStatusArray.add(_loansByStatus[LoanStatus.Pending], _loanStatusIndex[LoanStatus.Pending], loanId, LoanStatus.Pending);
244:
245:        openRequestCount[msg.sender] += 1;
246:        lastRequestBlock[msg.sender] = block.number;
247:
248:        emit LoanRequestSubmitted(loanId, msg.sender, walletReputation, loanAmount, loanDurationBlocks, block.number);
249:    }

321:    function borrow(	// @audit-issue
322:        uint256 loanId,
323:        uint256 tokenAmount
324:    ) external override whenNotPaused nonReentrant loanExists(loanId) onlyBorrower(loanId) {
325:        Loan storage loan = loans[loanId];
326:
327:        if (loan.status != LoanStatus.Approved) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Approved));
328:        if (tokenAmount == 0) revert UnllooErrors.InvalidAmount(tokenAmount, 1, type(uint256).max);
329:
330:        uint256 expiryBlock = loan.approvalBlock + APPROVED_LOAN_EXPIRY_BLOCKS;
331:        if (block.number > expiryBlock) revert UnllooErrors.ApprovedLoanExpired(loanId, loan.approvalBlock, expiryBlock);
332:
333:        if (_activeLoanByBorrower[msg.sender] != 0) revert UnllooErrors.HasActiveLoan(msg.sender);
334:
335:        address token = loan.token;
336:        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);
337:
338:        uint256 maxTokenAmount = getApprovedLoanAmount(loanId);
339:        if (tokenAmount > maxTokenAmount) revert UnllooErrors.InvalidAmount(tokenAmount, 1, maxTokenAmount);
340:
341:        LiquidityPool storage pool = pools[token];
342:
343:        if (pool.borrowedAmount > pool.totalLiquidity) revert UnllooErrors.InsufficientLiquidity(tokenAmount, 0);
344:        uint256 freeLiquidity = pool.totalLiquidity - pool.borrowedAmount;
345:        if (tokenAmount > freeLiquidity) revert UnllooErrors.InsufficientLiquidity(tokenAmount, freeLiquidity);
346:
347:        if (loan.loanDurationBlocks > MAX_BLOCKS_FOR_INTEREST) {
348:            revert UnllooErrors.InvalidDuration(loan.loanDurationBlocks, 1, MAX_BLOCKS_FOR_INTEREST);
349:        }
350:
351:        // Calculate fixed borrow rate based on current utilization
352:        uint256 borrowRateBps = _calculateBorrowRate(token);
353:
354:        loanInitialPrincipal[loanId] = tokenAmount;
355:
356:        loan.status = LoanStatus.Active;
357:        loan.principal = tokenAmount;
358:        loan.amountRepaid = 0;
359:        loan.startBlock = block.number;
360:        loan.deadlineBlock = block.number + loan.loanDurationBlocks;
361:        loan.protocolFee = 0;
362:        loan.interestAccrued = 0;
363:        loan.borrowRateBps = borrowRateBps; // Fixed rate for loan lifetime
364:        loan.lastAccrualBlock = block.number; // Initialize accrual tracking
365:
366:        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Approved], _loanStatusIndex[LoanStatus.Approved], loanId, LoanStatus.Approved);
367:        UnllooStatusArray.add(_loansByStatus[LoanStatus.Active], _loanStatusIndex[LoanStatus.Active], loanId, LoanStatus.Active);
368:
369:        _activeLoanByBorrower[loan.borrower] = loanId;
370:
371:        if (openRequestCount[loan.borrower] > 0) openRequestCount[loan.borrower] -= 1;
372:
373:        pool.borrowedAmount += tokenAmount;
374:        activeLoansPerPool[token] += 1;
375:
376:        _safeTransferExact(token, msg.sender, tokenAmount);
377:
378:        // Calculate expected interest using simple interest for event
379:        // Formula: I = P * r * t where t = blocksElapsed / blocksPerYear
380:        // Multiply first, divide last to avoid precision loss:
381:        // expectedInterest = (tokenAmount * borrowRateBps * loanDurationBlocks * BLOCK_TIME_SECONDS) / (10000 * SECONDS_PER_YEAR)
382:        uint256 secondsPerYear = 365 * 24 * 60 * 60;
383:        uint256 expectedInterest = (tokenAmount * borrowRateBps * loan.loanDurationBlocks * BLOCK_TIME_SECONDS) / (10000 * secondsPerYear);
384:        uint256 expectedTotalOwed = tokenAmount + expectedInterest;
385:
386:        emit LoanBorrowed(loanId, msg.sender, token, tokenAmount, expectedTotalOwed, block.number);
387:    }

