640:        LenderPosition storage position = lenderPositions[msg.sender][token];
641:        if (position.lender == address(0) || position.depositedAmount == 0) revert UnllooErrors.InvalidAmount(amount, 1, 0);
642:        if (amount > position.depositedAmount) revert UnllooErrors.InvalidAmount(amount, 1, position.depositedAmount);
643:
644:        LiquidityPool storage pool = pools[token];
645:        if (pool.borrowedAmount > pool.totalLiquidity) revert UnllooErrors.InsufficientLiquidity(amount, 0);
646:
647:        uint256 freeLiquidity = pool.totalLiquidity - pool.borrowedAmount;
648:        if (amount > freeLiquidity) revert UnllooErrors.InsufficientLiquidity(amount, freeLiquidity);
649:
650:        uint256 accrued = lenderAccruedInterest[msg.sender][token];
651:
652:        uint256 interestToPay;
653:        if (amount == position.depositedAmount) {
654:            // Full withdrawal: pay all interest
655:            interestToPay = accrued;
656:        } else {
657:            // Partial: pay pro-rata
658:            interestToPay = (accrued * amount) / position.depositedAmount;
659:        }
660:
661:        // Update storage before external call
662:        position.depositedAmount -= amount;
663:        position.lastWithdrawBlock = block.number;
664:        pool.totalLiquidity -= amount;
665:
666:        if (interestToPay > 0) {
667:            lenderAccruedInterest[msg.sender][token] = accrued - interestToPay;
668:        }
669:
670:        if (position.depositedAmount == 0) {
671:            delete lenderPositions[msg.sender][token];
672:            delete lenderSupplyIndex[msg.sender][token];
673:            delete lenderAccruedInterest[msg.sender][token];
674:            activeLenderCount[token] -= 1;
675:        }
676:
677:        uint256 totalPayout = amount + interestToPay;
678:
679:        // Ensure we do not spend reserved protocol fees
680:        uint256 balance = IERC20(token).balanceOf(address(this));
681:        if (balance < totalPayout) revert UnllooErrors.NotEnoughCash(totalPayout, balance);
682:        if (balance - totalPayout < protocolFees[token]) revert UnllooErrors.NotEnoughCash(totalPayout, balance - protocolFees[token]);
683:
684:        _safeTransferExact(token, msg.sender, totalPayout);
685:
686:        emit LiquidityWithdrawn(msg.sender, token, amount, interestToPay, totalPayout, block.number);
687:    }

1117:    function updatePoolRateCurve(	// @audit-issue
1118:        address token,
1119:        uint256 baseRateBps,
1120:        uint256 optimalUtilizationBps,
1121:        uint256 slope1Bps,
1122:        uint256 slope2Bps,
1123:        uint256 protocolFeeBps
1124:    )
1125:        external
1126:        override
1127:        onlyOwner
1128:        validPool(token)
1129:    {
1130:        // Validation: baseRateBps max 10%
1131:        if (baseRateBps > 1000) {
1132:            revert UnllooErrors.InvalidRateCurveParam(token, "baseRateBps", baseRateBps);
1133:        }
1134:
1135:        // Validation: optimalUtilizationBps between 50% and 95%
1136:        if (optimalUtilizationBps < 5000 || optimalUtilizationBps > 9500) {
1137:            revert UnllooErrors.InvalidRateCurveParam(token, "optimalUtilizationBps", optimalUtilizationBps);
1138:        }
1139:
1140:        // Validation: slope1Bps max 20%
1141:        if (slope1Bps > 2000) {
1142:            revert UnllooErrors.InvalidRateCurveParam(token, "slope1Bps", slope1Bps);
1143:        }
1144:
1145:        // Validation: slope2Bps max 100%
1146:        if (slope2Bps > 10000) {
1147:            revert UnllooErrors.InvalidRateCurveParam(token, "slope2Bps", slope2Bps);
1148:        }
1149:
1150:        // Validation: protocolFeeBps max 50%
1151:        if (protocolFeeBps > 5000) {
1152:            revert UnllooErrors.InvalidRateCurveParam(token, "protocolFeeBps", protocolFeeBps);
1153:        }
1154:
1155:        // Validation: max possible rate must not exceed MAX_BORROWER_RATE
1156:        uint256 maxPossibleRate = baseRateBps + slope1Bps + slope2Bps;
1157:        if (maxPossibleRate > MAX_BORROWER_RATE) {
1158:            revert UnllooErrors.InvalidRateCurveParam(token, "totalMaxRate", maxPossibleRate);
1159:        }
1160:
1161:        _poolRateCurve[token] = RateCurveParams({
1162:            baseRateBps: baseRateBps,
1163:            optimalUtilizationBps: optimalUtilizationBps,
1164:            slope1Bps: slope1Bps,
1165:            slope2Bps: slope2Bps,
1166:            protocolFeeBps: protocolFeeBps
1167:        });
1168:
1169:        emit InterestRatesUpdated(
1170:            token,
1171:            baseRateBps,
1172:            optimalUtilizationBps,
1173:            slope1Bps,
1174:            slope2Bps,
1175:            protocolFeeBps,
1176:            block.number
1177:        );
1178:    }

1410:    function _finalizeRepaid(uint256 loanId, Loan storage loan) internal {	// @audit-issue
1411:        LoanStatus beforeStatus = loan.status;
1412:        loan.status = LoanStatus.Repaid;
1413:
1414:        if (beforeStatus == LoanStatus.UnpaidDebt && unpaidDebtLoanCount[loan.borrower] > 0) {
1415:            unpaidDebtLoanCount[loan.borrower] -= 1;
1416:        }
1417:
1418:        if (_activeLoanByBorrower[loan.borrower] == loanId) {
1419:            _activeLoanByBorrower[loan.borrower] = 0;
1420:        }
1421:
1422:        // per-pool counters
1423:        address token = loan.token;
1424:        if (beforeStatus == LoanStatus.Active) {
1425:            if (activeLoansPerPool[token] > 0) activeLoansPerPool[token] -= 1;
1426:        } else if (beforeStatus == LoanStatus.UnpaidDebt) {
1427:            if (unpaidDebtLoansPerPool[token] > 0) unpaidDebtLoansPerPool[token] -= 1;
1428:        }
1429:
1430:        UnllooStatusArray.remove(_loansByStatus[beforeStatus], _loanStatusIndex[beforeStatus], loanId, beforeStatus);
1431:        UnllooStatusArray.add(_loansByStatus[LoanStatus.Repaid], _loanStatusIndex[LoanStatus.Repaid], loanId, LoanStatus.Repaid);
1432:    }
